import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Cookie } from "lucide-react";
import { getConsent, setConsent, onConsentChange } from "@/lib/cookieConsent";

/**
 * GDPR cookie / tracking consent banner.
 * Shows on first visit; remembers choice in localStorage.
 * Three options: Accept all / Essential only / Customize (link to privacy policy).
 */
export const CookieConsentBanner = () => {
  const { t } = useTranslation();
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    setVisible(!getConsent());
    const off = onConsentChange((s) => setVisible(!s));
    return off;
  }, []);

  if (!visible) return null;

  const handleAccept = () => {
    setConsent("accepted");
    setVisible(false);
  };

  const handleEssential = () => {
    setConsent("essential");
    setVisible(false);
  };

  return (
    <div
      role="dialog"
      aria-live="polite"
      aria-label={t("consent.title", "Cookie 与数据使用")}
      className="fixed bottom-0 left-0 right-0 z-[100] p-3 md:p-4 pointer-events-none"
    >
      <div className="mx-auto max-w-3xl bg-background border border-border shadow-2xl rounded-xl p-4 md:p-5 pointer-events-auto">
        <div className="flex flex-col md:flex-row md:items-center gap-4">
          {/* Left: icon + text */}
          <div className="flex items-start gap-3 flex-1 min-w-0">
            <Cookie className="h-5 w-5 text-primary shrink-0 mt-0.5" />
            <div className="flex-1 min-w-0">
              <h2 className="font-semibold text-sm md:text-base mb-1">
                {t("consent.title", "我们使用 Cookie 与访问数据")}
              </h2>
              <p className="text-xs md:text-sm text-muted-foreground leading-relaxed">
                {t(
                  "consent.description",
                  "为了保障安全与诊断故障，我们会自动记录错误信息（必要）。若您同意，我们还会记录访问路径、停留时长与地理位置以改善服务体验。所有数据保留 30 天后自动删除。"
                )}{" "}
                <Link to="/privacy-policy" className="text-primary underline underline-offset-2">
                  {t("consent.learnMore", "了解更多")}
                </Link>
              </p>
            </div>
          </div>

          {/* Right: action buttons */}
          <div className="flex flex-row gap-2 md:shrink-0 md:items-center">
            <Button
              size="sm"
              variant="outline"
              onClick={handleEssential}
              className="flex-1 md:flex-none"
            >
              {t("consent.essentialOnly", "仅必要")}
            </Button>
            <Button size="sm" onClick={handleAccept} className="flex-1 md:flex-none">
              {t("consent.acceptAll", "全部同意")}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CookieConsentBanner;
